(function(){
  function Graph(){this._nodes=new Map();this._edges=new Map();}
  Graph.prototype.hasNode=function(id){return this._nodes.has(id);};
  Graph.prototype.addNode=function(id,attrs){this._nodes.set(id,Object.assign({},attrs));};
  Graph.prototype.dropNode=function(id){this._nodes.delete(id);for(const k of this._edges.keys()){const e=this._edges.get(k);if(e.from===id||e.to===id)this._edges.delete(k);}};
  Graph.prototype.setNodeAttribute=function(id,key,val){if(this._nodes.has(id)){this._nodes.get(id)[key]=val;}};
  Graph.prototype.getNodeAttribute=function(id,key){return this._nodes.has(id)?this._nodes.get(id)[key]:undefined;};
  Graph.prototype.getNodeAttributes=function(id){return this._nodes.get(id)||{};};
  Graph.prototype.hasEdge=function(key){return this._edges.has(key);};
  Graph.prototype.addEdgeWithKey=function(key,from,to,attrs){this._edges.set(key,{from:from,to:to,attrs:Object.assign({},attrs)});};
  window.graphology={Graph:Graph};
})();
